select

from osg_mock_practice


        and practice_type = #{practiceType}


        and status = #{status}


        and (
            student_name like concat('%', #{keyword}, '%')
            or request_content like concat('%', #{keyword}, '%')
        )


        and status = 'pending'


order by submitted_at desc, practice_id desc

